 64→	public async process({
 65→		style,
 66→		allCategories,
 67→	}: {
 68→		style: MMSStyleToProcess;
 69→		allCategories: MMSAllStyleCategory[];
 70→	}): Promise<boolean> {
 71→		try {
 72→			if (!this.isProductAllowedToProcess(style)) {
 73→				this.logger.debug(`Style ${style.id} is not allowed to process.`);
 74→				await Promise.all([
 75→					this.deleteFromAlgoliaIndex({ styleId: style.id }),
 76→					this.deleteCondensedFeatures({ styleId: style.id }),
 77→				]);
 78→				return false;
 79→			}
 80→
 81→			const featuresRelatedFields = this.extractFeaturesRelatedFields({
 82→				style,
 83→				allCategories,
 84→			});
 85→
 86→			const isProductActive = this.checkIsProductActive({
 87→				status: style.status,
 88→				colors: style.colors,
 89→			});
 90→
 91→			await this.saveStyleToDatabase({ style, allCategories, isProductActive });
 92→
 93→			const newHash = hashFromObject({
 94→				obj: featuresRelatedFields as unknown as Record<string, unknown>,
 95→			});
 96→			const storedHash = await this.getStoredHash({ styleId: style.id });
 97→
 98→			const isCondensedFeaturesExists =
 99→				await this.condensedFeaturesService.getCondensedFeature({
100→					styleId: style.id,
101→				});
102→
103→			const existingMvRecord = await this.stylesMvService.getByStyleId({
104→				styleId: style.id,
105→			});
106→			const hasEmbeddingText = Boolean(existingMvRecord?.embedding_text);
107→
108→			if (!storedHash) {
109→				if (!isCondensedFeaturesExists) {
110→					this.logger.debug(
111→						`Style ${style.id}: no hash, no features. Creating new features`,
112→					);
113→
114→					const condensedFeatures = isProductActive
115→						? await this.generateLLMFeatures({ style, featuresRelatedFields })
116→						: [];
117→					await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
118→					await this.createHash({ styleId: style.id, hash: newHash });
119→					if (isProductActive) {
120→						await this.generateAndSaveEmbeddingText({
121→							style,
122→							allCategories,
123→							condensedFeatures,
124→						});
125→					}
126→					await this.updateAlgoliaIndex({
127→						style,
128→						allCategories,
129→						condensedFeatures,
130→					});
131→				} else {
132→					this.logger.debug(
133→						`Style ${style.id}: no hash, but features exist. Generating hash`,
134→					);
135→					await this.createHash({ styleId: style.id, hash: newHash });
136→					if (isProductActive && !hasEmbeddingText) {
137→						await this.generateAndSaveEmbeddingText({
138→							style,
139→							allCategories,
140→							condensedFeatures: isCondensedFeaturesExists.condensed_features,
141→						});
142→					}
143→					await this.updateAlgoliaIndex({
144→						style,
145→						allCategories,
146→						condensedFeatures: isCondensedFeaturesExists.condensed_features,
147→					});
148→				}
149→
150→				return true;
151→			} else if (storedHash && !compareHashes({ hash1: newHash, hash2: storedHash })) {
152→				this.logger.debug(`Style ${style.id}: hash changed, updating features and index`);
153→
154→				const condensedFeatures = isProductActive
155→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
156→					: (isCondensedFeaturesExists?.condensed_features ?? []);
157→				await this.updateStoredHash({ styleId: style.id, hash: newHash });
158→				await this.updateCondensedFeatures({ styleId: style.id, condensedFeatures });
159→				if (isProductActive) {
160→					await this.generateAndSaveEmbeddingText({
161→						style,
162→						allCategories,
163→						condensedFeatures,
164→					});
165→				}
166→				await this.updateAlgoliaIndex({
167→					style,
168→					allCategories,
169→					condensedFeatures,
170→				});
171→				return true;
172→			} else if (storedHash && !isCondensedFeaturesExists) {
173→				this.logger.debug(
174→					`Style ${style.id}: hash exists, but no features exist. Creating new features`,
175→				);
176→				const condensedFeatures = isProductActive
177→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
178→					: [];
179→				await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
180→				if (isProductActive) {
181→					await this.generateAndSaveEmbeddingText({
182→						style,
183→						allCategories,
184→						condensedFeatures,
185→					});
186→				}
187→				await this.updateAlgoliaIndex({
188→					style,
189→					allCategories,
190→					condensedFeatures,
191→				});
192→				return true;
193→			}
194→
195→			if (isProductActive && !hasEmbeddingText) {
196→				await this.generateAndSaveEmbeddingText({
197→					style,
198→					allCategories,
199→					condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
200→				});
201→			}
202→
203→			await this.updateAlgoliaIndex({
204→				style,
205→				allCategories,
206→				condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
207→			});
208→			this.logger.debug(`Style ${style.id}: hash is the same, no changes needed`);
209→			return false;
210→		} catch (error) {
211→			this.logger.error(`Error processing style ${style.id}:`, error);
212→			throw error;
213→		}
214→	}
