434→			const errorMessage = error instanceof Error ? error.message : String(error);
435→			const isTokenLimitError = errorMessage.includes('maximum context length');
436→
437→			if (isTokenLimitError) {
438→				this.logger.warn(
439→					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
