671→	private getBroadCategoryNames({
672→		categories,
673→		allCategories,
674→	}: {
675→		styleId?: number;
676→		categories: MMSStyleToProcess['categories'];
677→		allCategories: MMSAllStyleCategory[];
678→	}): string[] {
679→		const activeCategories = categories
680→			.map((cat) => {
681→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
682→				if (fullCategory) {
683→					cat['parent'] = fullCategory;
684→				}
685→				return cat;
686→			})
687→			.filter((cat) => cat.active);
688→
689→		const allParents = activeCategories
690→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
691→			.filter(Boolean) as MMSAllStyleCategory[];
692→
693→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
694→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
695→				return acc;
696→			}
697→
698→			if (!acc.some((p) => p._id === parent._id)) {
699→				acc.push(parent);
700→			}
701→
702→			return acc;
703→		}, []);
704→
705→		const names = uniqueParents
706→			.map((parent) => parent['name'])
707→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
708→
709→		return [...new Set(names)];
710→	}
