712→	private getStylesSubcategories({
713→		categories,
714→		allCategories,
715→	}: {
716→		categories: MMSStyleToProcess['categories'];
717→		allCategories: MMSAllStyleCategory[];
718→	}): string[] {
719→		const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
720→
721→		const childCategories: string[] = [];
722→
723→		for (const category of activeCategories) {
724→			const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
725→
726→			if (!hasChildren && category.name) {
727→				childCategories.push(category.name);
728→			}
729→		}
730→
731→		return [...new Set(childCategories)];
732→	}
