738→	private calculateLink({
739→		style,
740→		allCategories,
741→	}: {
742→		style: MMSStyleToProcess;
743→		allCategories: MMSAllStyleCategory[];
744→	}): Breadcrumb | null {
745→		function urlFriendly(str: string): string {
746→			return str
747→				.toLowerCase()
748→				.replace(/&reg;/g, '®')
749→				.replace(/\//g, '-')
750→				.replace(/\s+/g, '-')
751→				.replace(/[^\+\-0-9_a-z]/g, '')
752→				.replace(/^-+|-+$/g, '')
753→				.replace(/-+/g, '-');
754→		}
755→
756→		const primaryCategory = style.primary_category;
757→
758→		if (!primaryCategory) {
759→			return null;
760→		}
761→
762→		const primaryCatParent = allCategories.find(
763→			(cat) => cat._id === primaryCategory.parent_id,
764→		);
765→
766→		const primaryCatParentName = primaryCatParent?.['name'] as string;
767→		const categoryName = primaryCategory.name;
768→
769→		const firstPartLink = !primaryCatParent
770→			? '/products'
771→			: `/products/${urlFriendly(primaryCatParentName)}`;
772→
773→		const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
774→
775→		return {
776→			name: style.name,
777→			path: path,
778→		};
779→	}
780→
781→	private extractCategoryIds({ style }: { style: MMSStyleToProcess }): number[] {
782→		const activeCategories = style.categories.filter((cat) => cat.active);
783→		return activeCategories.map((cat) => cat.id);
784→	}
785→
786→	private extractCategoriesWithParents({
787→		categoryIds,
788→		allCategories,
789→	}: {
790→		categoryIds: number[];
791→		allCategories: MMSAllStyleCategory[];
792→	}): number[] {
793→		const allCategoryIds = new Set<number>();
794→
795→		for (const categoryId of categoryIds) {
796→			allCategoryIds.add(categoryId);
797→
798→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
799→			for (const parentId of parentIds) {
800→				allCategoryIds.add(parentId);
801→			}
802→		}
803→
804→		return Array.from(allCategoryIds).sort((a, b) => a - b);
805→	}
806→
807→	private getAllParentCategoryIds({
808→		categoryId,
809→		allCategories,
810→	}: {
811→		categoryId: number;
812→		allCategories: MMSAllStyleCategory[];
813→	}): number[] {
814→		const parents: number[] = [];
815→		const category = allCategories.find((cat) => cat._id === categoryId);
816→
817→		if (!category?.['parent_id']) {
818→			return parents;
819→		}
820→
821→		let currentParentId = category['parent_id'] as number;
822→
823→		while (currentParentId) {
824→			parents.push(currentParentId);
825→
826→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
827→			if (!parentCategory?.['parent_id']) {
828→				break;
829→			}
830→
831→			currentParentId = parentCategory['parent_id'] as number;
832→		}
833→
834→		return parents;
835→	}
836→
837→	private getRootCategoryId({
838→		style,
839→		allCategories,
840→	}: {
841→		style: MMSStyleToProcess;
842→		allCategories: MMSAllStyleCategory[];
843→	}): number | null {
844→		if (!style.primary_category) {
845→			return null;
846→		}
847→
848→		const primaryCategory = allCategories.find(
849→			(cat) => cat._id === style.primary_category_id,
850→		);
851→		if (!primaryCategory) {
852→			return null;
853→		}
854→
855→		let currentCategory = primaryCategory;
856→		while (currentCategory['parent_id']) {
857→			const parentCategory = allCategories.find(
858→				(cat) => cat._id === currentCategory['parent_id'],
859→			);
860→			if (!parentCategory) break;
861→			currentCategory = parentCategory;
862→		}
863→
864→		return !currentCategory['parent_id'] ? currentCategory._id : null;
865→	}
866→}
