  1→import { Injectable, Logger } from '@nestjs/common';
  2→import { OpenAI } from 'openai';
  3→
  4→import { getEnv } from '@utils/get-env-variable.util';
  5→
  6→import { OPENAI_API_KEY } from '@constants/env-variables.constant';
  7→
  8→import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';
  9→
 10→import { LogExecution } from '@decorators/log-execution.decorator';
 11→
 12→export interface ProductFeatureResponse {
 13→	description?: string[];
 14→	error?: string;
 15→}
 16→
 17→export interface EmbeddingTextResponse {
 18→	text: string;
 19→}
 20→
 21→export interface ProductEmbeddingInput {
 22→	name: string;
 23→	product_type: string | null;
 24→	style_type: string | null;
 25→	primary_category_name: string | null;
 26→	sub_category_names: string[] | null;
 27→	broad_category_names: string[] | null;
 28→	features: string | null;
 29→	general_comments: string | null;
 30→	decoration_method: string | null;
 31→	manufacturer: string | null;
 32→	brand: string[] | null;
 33→	condensed_features: string[] | null;
 34→	sizes: string[] | null;
 35→}
 36→
 37→@Injectable()
 38→export class OpenAIService {
 39→	private readonly logger = new Logger(OpenAIService.name);
 40→	private readonly openai: OpenAI;
 41→
 42→	constructor() {
 43→		const apiKey = getEnv<string>({ key: OPENAI_API_KEY });
 44→		this.openai = new OpenAI({ apiKey, baseURL: 'https://api.openai.com/v1' });
 45→	}
 46→
 47→	async generateProductFeatures({
 48→		productInfo,
 49→	}: {
 50→		productInfo: MMSStyleToProcess;
 51→	}): Promise<ProductFeatureResponse> {
 52→		try {
 53→			this.logger.log(`Processing product features for id: ${productInfo.id}`);
 54→
 55→			const prompt = this.buildPrompt({ productInfo });
 56→
 57→			const response = await this.getOpenAIResponse(prompt);
 58→
 59→			this.logger.log(`Successfully generated features for id: ${productInfo.id}`);
 60→			return response;
 61→		} catch (error) {
 62→			this.logger.error(`Error processing product ${productInfo.id}:`, error);
 63→			return {
 64→				error: `Failed to process product: ${error instanceof Error ? error.message : 'Unknown error'}`,
 65→			};
 66→		}
 67→	}
 68→
 69→	@LogExecution({
 70→		paramFormatter: (params: [{ product: ProductEmbeddingInput }]) => ({
 71→			name: params[0].product.name,
 72→		}),
 73→	})
 74→	async generateEmbeddingText({
 75→		product,
 76→	}: {
 77→		product: ProductEmbeddingInput;
 78→	}): Promise<EmbeddingTextResponse> {
 79→		const productData = {
 80→			name: product.name,
 81→			product_type: product.product_type,
 82→			style_type: product.style_type,
 83→			category: product.primary_category_name,
 84→			subcategories: product.sub_category_names,
 85→			broad_categories: product.broad_category_names,
 86→			features: product.features,
 87→			description: product.general_comments,
 88→			decoration_method: product.decoration_method,
 89→			manufacturer: product.manufacturer,
 90→			brand: product.brand,
 91→			condensed_features: product.condensed_features,
 92→			sizes: product.sizes,
 93→		};
 94→
 95→		const completion = await this.openai.chat.completions.create({
 96→			messages: [
 97→				{
 98→					role: 'system',
 99→					content: `You are a senior data engineer and data analyst who is an expert in generating text embeddings for neural product search.
100→Your task: given product data, produce a single natural-language paragraph optimized for a distilroberta-v1 embedding model (512 token limit).
101→
102→Rules:
103→- Write fluent, human-readable sentences — no bullet points, no pipe delimiters, no markdown.
104→- Lead with the product name and what it is.
105→- Describe key physical features, materials, and use cases.
106→- Highlight occasions, events, and audiences this product is ideal for.
107→- Include the decoration/customization method naturally.
108→- Mention the manufacturer/brand only once if relevant.
109→- Skip null/empty fields silently — never say "unknown" or "N/A".
110→- Do NOT invent features not present in the input data.
111→- Output ONLY valid JSON: {"text": "your paragraph here"}`,
112→				},
113→				{
114→					role: 'user',
115→					content: `Generate embedding text for this product:\n${JSON.stringify(productData)}`,
116→				},
117→			],
118→			model: 'gpt-4o-mini',
119→			response_format: { type: 'json_object' },
120→			temperature: 0.3,
121→			max_tokens: 350,
122→		});
123→
124→		if (!completion.choices[0]?.message.content) {
125→			throw new Error('Empty response from OpenAI');
126→		}
127→
128→		const parsed = JSON.parse(
129→			completion.choices[0].message.content,
130→		) as EmbeddingTextResponse;
131→
132→		if (!parsed.text || typeof parsed.text !== 'string') {
133→			this.logger.error(
134→				'Invalid response format from OpenAI:',
135→				JSON.stringify(completion.choices[0].message.content),
136→			);
137→			return { text: '' };
138→		}
139→
140→		return parsed;
141→	}
142→
143→	private buildPrompt({ productInfo }: { productInfo: MMSStyleToProcess }): string {
144→		return `
145→The description should be present and be suitable for product recommendation model without mentioning names and brands.
146→Description should be an array of feature strings.
147→Response format: { "description": feature[] } in JSON format.
148→
149→Product in JSON format: ${JSON.stringify(productInfo, null, 2)}
150→`;
151→	}
152→
153→	private async getOpenAIResponse(prompt: string): Promise<ProductFeatureResponse> {
154→		const completion = await this.openai.chat.completions.create({
155→			messages: [
156→				{
157→					role: 'system',
158→					content: `You are an expert in data preprocessing and feature engineering for machine learning.
159→				Your job is prepare data for training Related Products model based on "Content-based" approach.
160→				Your need to define key features, product details and important words for products and build array of features.
161→          `,
162→				},
163→				{ role: 'user', content: [{ type: 'text', text: prompt }] },
164→			],
165→			model: 'gpt-4o',
166→			response_format: { type: 'json_object' },
167→		});
168→
169→		if (!completion.choices[0]) {
170→			return { error: 'No response from OpenAI' };
171→		}
172→
173→		const content = completion.choices[0].message.content;
174→		if (!content) {
175→			return { error: 'Empty response from OpenAI' };
176→		}
177→
178→		try {
179→			const parsedResponse = JSON.parse(content) as ProductFeatureResponse;
180→
181→			const fieldNames = Object.keys(parsedResponse);
182→			const firstFieldName = fieldNames[0] as keyof ProductFeatureResponse;
183→
184→			if (!parsedResponse.description) {
185→				const fieldValue = parsedResponse[firstFieldName];
186→				return {
187→					description:
188→						typeof fieldValue === 'string'
189→							? (JSON.parse(fieldValue) as string[])
190→							: (fieldValue ?? []),
191→					...parsedResponse,
192→				};
193→			}
194→
195→			return parsedResponse;
196→		} catch (parseError) {
197→			this.logger.error('Failed to parse OpenAI response:', parseError);
198→			return { error: 'Failed to parse OpenAI response' };
199→		}
200→	}
201→}
